public static long solve(long[] nums, long k) {
    if (nums.length == 1) {
        return 0;
    }

    Arrays.sort(nums);
    long minRemove = nums.length;

    for (int i = 0; i < nums.length; i++) {
        int j = i;
        while (j < nums.length) {
            long maxVal = nums[j];
            long minVal = nums[i];
            if (maxVal <= minVal * k) {
                long removeCount = nums.length - (j - i + 1);
                minRemove = Math.min(minRemove, removeCount);
                break;
            } else {
                j++;
            }
        }
    }

    return minRemove;
}
